import React from "react";
import { NavLink } from "react-router-dom";
import "./DashboardSidebar.css";
import { isAdmin } from "./auth";

const DashboardSidebar = () => {
  const isUserAdmin = isAdmin();

  return (
    <div className="dashboard-sidebar">

      {/* ================= DASHBOARD ================= */}
      <NavLink to="/dashboard" end className="sidebar-title">
        Dashboard
      </NavLink>

      {/* ================= COMMON ================= */}
      <NavLink to="/dashboard/employee-details">
        Employees
      </NavLink>

      {/* ================= ADMIN MENUS ================= */}
      {isUserAdmin && (
        <>
          <NavLink to="/dashboard/departments">
            Departments
          </NavLink>

          <NavLink to="/dashboard/appraisal">
            Appraisal
          </NavLink>

          <NavLink to="/dashboard/employee-details/leaves">
            Leave Requests
          </NavLink>

          <NavLink to="/dashboard/recruitment">
            Recruitment
          </NavLink>

          <NavLink to="/dashboard/view-applicants">
            View Job Applications
          </NavLink>
        </>
      )}

      {/* ================= EMPLOYEE MENUS ================= */}
      {!isUserAdmin && (
        <>
          <NavLink to="/dashboard/employee-jobs">
            Job Openings
          </NavLink>

          <NavLink to="/dashboard/my-applications">
            My Applications
          </NavLink>

          {/* Employee Offer Letters */}
          <NavLink to="/dashboard/my-offers">
            My Offers
          </NavLink>

          <NavLink to="/dashboard/employee-details/leave-history">
            Leave History
          </NavLink>
        </>
      )}

      {/* ================= COMMON (BOTTOM) ================= */}
      <NavLink to="/dashboard/timesheet">
        Timesheet
      </NavLink>

      <NavLink to="/dashboard/timesheet/history">
        Timesheet History
      </NavLink>

      <NavLink to="/dashboard/calendar">
        Calendar
      </NavLink>

    </div>
  );
};

export default DashboardSidebar;
